Here's the minimal refactor of `reconcileBatch` to async/await, preserving the `next(err)` error delivery contract:

```js
async function reconcileBatch(batch, next) {
  try {
    const rows = await db.fetchRows(batch);
    const results = applyRules(rows);
    await db.save(results);
    emitMetrics(results);
    next(null);
  } catch (err) {
    next(err);
  }
}
```

